<?php
namespace App\Http\Requests\Crm; use Illuminate\Foundation\Http\FormRequest; use Illuminate\Validation\Rule; class StoreProformaPaymentRequest extends FormRequest { public function authorize():bool{return(bool)$this->user()?->can('crm.proformas.record_payment');} public function rules():array{return ['amount'=>['required','numeric','gt:0'],'payment_date'=>['required','date'],'payment_mode'=>['required',Rule::in(['cash','bank_transfer','upi','card','cheque','online','other'])],'reference_number'=>['nullable','string','max:255'],'notes'=>['nullable','string','max:5000']];} }
